1	package middleware
2	
3	import (
4		"fmt"
5		"net/http"
6		"strings"
7		"time"
8	
9		"github.com/golang-jwt/jwt/v5"
10		"github.com/labstack/echo/v4"
11		"github.com/sirupsen/logrus"
12	
13		"medops/internal/models"
14	)
15	
16	// Context keys for user info
17	const (
18		contextKeyUserID   = "user_id"
19		contextKeyUserRole = "user_role"
20	)
21	
22	// GetUserID extracts the user_id from the echo context.
23	func GetUserID(c echo.Context) string {
24		val, _ := c.Get(contextKeyUserID).(string)
25		return val
26	}
27	
28	// GetUserRole extracts the user_role from the echo context.
29	func GetUserRole(c echo.Context) string {
30		val, _ := c.Get(contextKeyUserRole).(string)
31		return val
32	}
33	
34	// GenerateToken creates a JWT token valid for 24 hours with the given user ID, role, and secret.
35	func GenerateToken(userID, role, secret string) (string, error) {
36		claims := jwt.MapClaims{
37			"user_id": userID,
38			"role":    role,
39			"exp":     time.Now().Add(24 * time.Hour).Unix(),
40		}
41		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
42		return token.SignedString([]byte(secret))
43	}
44	
45	// JWTAuth returns middleware that validates a Bearer token from the Authorization header.
46	// On success it sets "user_id" and "user_role" in the echo context.
47	func JWTAuth(secret string) echo.MiddlewareFunc {
48		return func(next echo.HandlerFunc) echo.HandlerFunc {
49			return func(c echo.Context) error {
50				authHeader := c.Request().Header.Get("Authorization")
51				if authHeader == "" {
52					return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
53						Error: "Missing authorization header",
54						Code:  http.StatusUnauthorized,
55					})
56				}
57	
58				parts := strings.SplitN(authHeader, " ", 2)
59				if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
60					return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
61						Error: "Invalid authorization header format",
62						Code:  http.StatusUnauthorized,
63					})
64				}
65	
66				tokenString := parts[1]
67				token, err := jwt.Parse(tokenString, func(t *jwt.Token) (interface{}, error) {
68					if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
69						return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
70					}
71					return []byte(secret), nil
72				})
73				if err != nil || !token.Valid {
74					return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
75						Error:   "Invalid or expired token",
76						Code:    http.StatusUnauthorized,
77						Details: "Token validation failed",
78					})
79				}
80	
81				claims, ok := token.Claims.(jwt.MapClaims)
82				if !ok {
83					return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
84						Error: "Invalid token claims",
85						Code:  http.StatusUnauthorized,
86					})
87				}
88	
89				userID, _ := claims["user_id"].(string)
90				role, _ := claims["role"].(string)
91	
92				if userID == "" {
93					return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
94						Error: "Token missing user_id claim",
95						Code:  http.StatusUnauthorized,
96					})
97				}
98	
99				c.Set(contextKeyUserID, userID)
100				c.Set(contextKeyUserRole, role)
101	
102				return next(c)
103			}
104		}
105	}
106	
107	// RequireRole returns middleware that checks whether the authenticated user's role
108	// is among the allowed roles. Returns 403 Forbidden if not.
109	func RequireRole(roles ...string) echo.MiddlewareFunc {
110		allowed := make(map[string]struct{}, len(roles))
111		for _, r := range roles {
112			allowed[r] = struct{}{}
113		}
114	
115		return func(next echo.HandlerFunc) echo.HandlerFunc {
116			return func(c echo.Context) error {
117				userRole := GetUserRole(c)
118				if _, ok := allowed[userRole]; !ok {
119					return c.JSON(http.StatusForbidden, models.ErrorResponse{
120						Error:   "Insufficient permissions",
121						Code:    http.StatusForbidden,
122						Details: fmt.Sprintf("Role '%s' is not authorized for this resource", userRole),
123					})
124				}
125				return next(c)
126			}
127		}
128	}
129	
130	// RequestLogger returns middleware that logs each request using logrus with structured fields.
131	func RequestLogger() echo.MiddlewareFunc {
132		logger := logrus.New()
133		logger.SetFormatter(&logrus.JSONFormatter{})
134	
135		return func(next echo.HandlerFunc) echo.HandlerFunc {
136			return func(c echo.Context) error {
137				start := time.Now()
138	
139				err := next(c)
140				if err != nil {
141					c.Error(err)
142				}
143	
144				latency := time.Since(start)
145				req := c.Request()
146				res := c.Response()
147	
148				fields := logrus.Fields{
149					"method":     req.Method,
150					"path":       req.URL.Path,
151					"status":     res.Status,
152					"latency_ms": latency.Milliseconds(),
153					"remote_ip":  c.RealIP(),
154				}
155	
156				if userID := GetUserID(c); userID != "" {
157					fields["user_id"] = userID
158				}
159	
160				entry := logger.WithFields(fields)
161	
162				status := res.Status
163				switch {
164				case status >= 500:
165					entry.Error("Server error")
166				case status >= 400:
167					entry.Warn("Client error")
168				default:
169					entry.Info("Request handled")
170				}
171	
172				return nil
173			}
174		}
175	}
176	
177	// Recovery returns middleware that recovers from panics, logs the error, and returns a 500 response.
178	func Recovery() echo.MiddlewareFunc {
179		logger := logrus.New()
180		logger.SetFormatter(&logrus.JSONFormatter{})
181	
182		return func(next echo.HandlerFunc) echo.HandlerFunc {
183			return func(c echo.Context) error {
184				defer func() {
185					if r := recover(); r != nil {
186						logger.WithFields(logrus.Fields{
187							"panic":  fmt.Sprintf("%v", r),
188							"method": c.Request().Method,
189							"path":   c.Request().URL.Path,
190						}).Error("Panic recovered")
191	
192						c.JSON(http.StatusInternalServerError, models.ErrorResponse{
193							Error: "Internal server error",
194							Code:  http.StatusInternalServerError,
195						})
196					}
197				}()
198	
199				return next(c)
200			}
201		}
202	}
203	
