1	package handlers
2	
3	import (
4		"encoding/json"
5		"net/http"
6		"time"
7	
8		"github.com/labstack/echo/v4"
9		"github.com/sirupsen/logrus"
10		"golang.org/x/crypto/bcrypt"
11	
12		"medops/internal/middleware"
13		"medops/internal/models"
14		"medops/internal/repository"
15	)
16	
17	// AuthHandler handles authentication-related requests.
18	type AuthHandler struct {
19		repo      *repository.Repository
20		jwtSecret string
21	}
22	
23	// NewAuthHandler creates a new AuthHandler.
24	func NewAuthHandler(repo *repository.Repository, jwtSecret string) *AuthHandler {
25		return &AuthHandler{repo: repo, jwtSecret: jwtSecret}
26	}
27	
28	// Login authenticates a user and returns a JWT token.
29	func (h *AuthHandler) Login(c echo.Context) error {
30		var req models.LoginRequest
31		if err := c.Bind(&req); err != nil {
32			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
33				Error: "Invalid request body",
34				Code:  http.StatusBadRequest,
35			})
36		}
37	
38		if req.Username == "" || req.Password == "" {
39			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
40				Error:   "Validation failed",
41				Code:    http.StatusBadRequest,
42				Details: "Username and password are required",
43			})
44		}
45	
46		user, err := h.repo.GetUserByUsername(req.Username)
47		if err != nil {
48			logrus.WithField("username", req.Username).Warn("Login attempt for unknown user")
49			return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
50				Error: "Invalid credentials",
51				Code:  http.StatusUnauthorized,
52			})
53		}
54	
55		if !user.IsActive {
56			logrus.WithField("username", req.Username).Warn("Login attempt for inactive user")
57			return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
58				Error:   "Account disabled",
59				Code:    http.StatusUnauthorized,
60				Details: "This account has been deactivated",
61			})
62		}
63	
64		// Check lockout
65		if user.LockedUntil != nil && user.LockedUntil.After(time.Now()) {
66			logrus.WithField("username", req.Username).Warn("Login attempt for locked user")
67			return c.JSON(http.StatusForbidden, models.ErrorResponse{
68				Error:   "Account locked",
69				Code:    http.StatusForbidden,
70				Details: "Too many failed attempts. Please try again later.",
71			})
72		}
73	
74		// Verify password
75		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(req.Password)); err != nil {
76			// Increment failed attempts
77			if incErr := h.repo.IncrementFailedAttempts(user.ID); incErr != nil {
78				logrus.WithError(incErr).Error("Failed to increment failed attempts")
79			}
80	
81			// Lock account if >= 5 failed attempts (current attempt is already incremented)
82			if user.FailedAttempts+1 >= 5 {
83				if lockErr := h.repo.LockUser(user.ID, 15); lockErr != nil {
84					logrus.WithError(lockErr).Error("Failed to lock user")
85				}
86				logrus.WithField("username", req.Username).Warn("Account locked due to failed attempts")
87			}
88	
89			return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
90				Error: "Invalid credentials",
91				Code:  http.StatusUnauthorized,
92			})
93		}
94	
95		// Reset failed attempts on success
96		if err := h.repo.ResetFailedAttempts(user.ID); err != nil {
97			logrus.WithError(err).Error("Failed to reset failed attempts")
98		}
99	
100		// Generate JWT token
101		token, err := middleware.GenerateToken(user.ID, user.Role, h.jwtSecret)
102		if err != nil {
103			logrus.WithError(err).Error("Failed to generate JWT token")
104			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
105				Error: "Failed to generate authentication token",
106				Code:  http.StatusInternalServerError,
107			})
108		}
109	
110		// Audit log
111		h.repo.CreateAuditLog(&models.AuditLogEntry{
112			UserID:     user.ID,
113			Action:     "login",
114			EntityType: "user",
115			EntityID:   user.ID,
116		})
117	
118		logrus.WithField("user_id", user.ID).Info("User logged in successfully")
119	
120		return c.JSON(http.StatusOK, models.LoginResponse{
121			Token: token,
122			User:  *user,
123		})
124	}
125	
126	// Logout handles stateless JWT logout (no server-side action required).
127	func (h *AuthHandler) Logout(c echo.Context) error {
128		userID := middleware.GetUserID(c)
129	
130		h.repo.CreateAuditLog(&models.AuditLogEntry{
131			UserID:     userID,
132			Action:     "logout",
133			EntityType: "user",
134			EntityID:   userID,
135		})
136	
137		logrus.WithField("user_id", userID).Info("User logged out")
138	
139		return c.JSON(http.StatusOK, map[string]string{
140			"message": "Logged out successfully",
141		})
142	}
143	
144	// GetMe returns the currently authenticated user's profile.
145	func (h *AuthHandler) GetMe(c echo.Context) error {
146		userID := middleware.GetUserID(c)
147		if userID == "" {
148			return c.JSON(http.StatusUnauthorized, models.ErrorResponse{
149				Error: "Not authenticated",
150				Code:  http.StatusUnauthorized,
151			})
152		}
153	
154		user, err := h.repo.GetUserByID(userID)
155		if err != nil {
156			logrus.WithError(err).WithField("user_id", userID).Error("Failed to get user profile")
157			return c.JSON(http.StatusNotFound, models.ErrorResponse{
158				Error: "User not found",
159				Code:  http.StatusNotFound,
160			})
161		}
162	
163		return c.JSON(http.StatusOK, user)
164	}
165	
166	// ChangePassword updates the authenticated user's password.
167	func (h *AuthHandler) ChangePassword(c echo.Context) error {
168		userID := middleware.GetUserID(c)
169	
170		var req models.ChangePasswordRequest
171		if err := c.Bind(&req); err != nil {
172			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
173				Error: "Invalid request body",
174				Code:  http.StatusBadRequest,
175			})
176		}
177	
178		if req.OldPassword == "" || req.NewPassword == "" {
179			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
180				Error:   "Validation failed",
181				Code:    http.StatusBadRequest,
182				Details: "Both old and new passwords are required",
183			})
184		}
185	
186		if len(req.NewPassword) < 12 {
187			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
188				Error:   "Validation failed",
189				Code:    http.StatusBadRequest,
190				Details: "New password must be at least 12 characters long",
191			})
192		}
193	
194		user, err := h.repo.GetUserByID(userID)
195		if err != nil {
196			logrus.WithError(err).Error("Failed to get user for password change")
197			return c.JSON(http.StatusNotFound, models.ErrorResponse{
198				Error: "User not found",
199				Code:  http.StatusNotFound,
200			})
201		}
202	
203		// Verify old password
204		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(req.OldPassword)); err != nil {
205			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
206				Error:   "Invalid old password",
207				Code:    http.StatusBadRequest,
208				Details: "The current password you entered is incorrect",
209			})
210		}
211	
212		// Hash new password
213		hash, err := bcrypt.GenerateFromPassword([]byte(req.NewPassword), bcrypt.DefaultCost)
214		if err != nil {
215			logrus.WithError(err).Error("Failed to hash new password")
216			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
217				Error: "Failed to update password",
218				Code:  http.StatusInternalServerError,
219			})
220		}
221	
222		user.PasswordHash = string(hash)
223		user.UpdatedAt = time.Now()
224		if err := h.repo.UpdateUser(user); err != nil {
225			logrus.WithError(err).Error("Failed to update user password")
226			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
227				Error: "Failed to update password",
228				Code:  http.StatusInternalServerError,
229			})
230		}
231	
232		h.repo.CreateAuditLog(&models.AuditLogEntry{
233			UserID:     userID,
234			Action:     "change_password",
235			EntityType: "user",
236			EntityID:   userID,
237		})
238	
239		logrus.WithField("user_id", userID).Info("User changed password")
240	
241		details, _ := json.Marshal(map[string]string{"action": "password_changed"})
242		_ = details
243	
244		return c.JSON(http.StatusOK, map[string]string{
245			"message": "Password updated successfully",
246		})
247	}
248	
