166	// ChangePassword updates the authenticated user's password.
167	func (h *AuthHandler) ChangePassword(c echo.Context) error {
168		userID := middleware.GetUserID(c)
169	
170		var req models.ChangePasswordRequest
171		if err := c.Bind(&req); err != nil {
172			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
173				Error: "Invalid request body",
174				Code:  http.StatusBadRequest,
175			})
176		}
177	
178		if req.OldPassword == "" || req.NewPassword == "" {
179			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
180				Error:   "Validation failed",
181				Code:    http.StatusBadRequest,
182				Details: "Both old and new passwords are required",
183			})
184		}
185	
186		if len(req.NewPassword) < 12 {
187			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
188				Error:   "Validation failed",
189				Code:    http.StatusBadRequest,
190				Details: "New password must be at least 12 characters long",
191			})
192		}
193	
194		user, err := h.repo.GetUserByID(userID)
195		if err != nil {
196			logrus.WithError(err).Error("Failed to get user for password change")
197			return c.JSON(http.StatusNotFound, models.ErrorResponse{
198				Error: "User not found",
199				Code:  http.StatusNotFound,
200			})
201		}
202	
203		// Verify old password
204		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(req.OldPassword)); err != nil {
205			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
206				Error:   "Invalid old password",
207				Code:    http.StatusBadRequest,
208				Details: "The current password you entered is incorrect",
209			})
210		}
211	
212		// Hash new password
213		hash, err := bcrypt.GenerateFromPassword([]byte(req.NewPassword), bcrypt.DefaultCost)
214		if err != nil {
215			logrus.WithError(err).Error("Failed to hash new password")
216			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
217				Error: "Failed to update password",
218				Code:  http.StatusInternalServerError,
219			})
220		}
221	
222		user.PasswordHash = string(hash)
223		user.UpdatedAt = time.Now()
224		if err := h.repo.UpdateUser(user); err != nil {
225			logrus.WithError(err).Error("Failed to update user password")
226			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
227				Error: "Failed to update password",
228				Code:  http.StatusInternalServerError,
229			})
230		}
231	
232		h.repo.CreateAuditLog(&models.AuditLogEntry{
233			UserID:     userID,
234			Action:     "change_password",
235			EntityType: "user",
236			EntityID:   userID,
237		})
238	
239		logrus.WithField("user_id", userID).Info("User changed password")
240	
241		details, _ := json.Marshal(map[string]string{"action": "password_changed"})
242		_ = details
243	
244		return c.JSON(http.StatusOK, map[string]string{
245			"message": "Password updated successfully",
246		})
247	}
