287	// Receive handles inventory receipt (stock in).
288	func (h *InventoryHandler) Receive(c echo.Context) error {
289		var req models.ReceiveRequest
290		if err := c.Bind(&req); err != nil {
291			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
292				Error: "Invalid request body",
293				Code:  http.StatusBadRequest,
294			})
295		}
296	
297		// Validate
298		if req.SKUID == "" {
299			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
300				Error:   "Validation failed",
301				Code:    http.StatusBadRequest,
302				Details: "SKU ID is required",
303			})
304		}
305		if req.Quantity <= 0 {
306			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
307				Error:   "Validation failed",
308				Code:    http.StatusBadRequest,
309				Details: "Quantity must be greater than 0",
310			})
311		}
312		if req.ReasonCode == "" {
313			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
314				Error:   "Validation failed",
315				Code:    http.StatusBadRequest,
316				Details: "Reason code is required",
317			})
318		}
319		if req.ExpirationDate == "" {
320			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
321				Error:   "Validation failed",
322				Code:    http.StatusBadRequest,
323				Details: "Expiration date is required",
324			})
325		}
326	
327		// Parse and validate expiration date is in the future
328		expDate, err := time.Parse("2006-01-02", req.ExpirationDate)
329		if err != nil {
330			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
331				Error:   "Validation failed",
332				Code:    http.StatusBadRequest,
333				Details: "Invalid expiration date format. Use YYYY-MM-DD",
334			})
335		}
336		if !expDate.After(time.Now().Truncate(24 * time.Hour)) {
337			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
338				Error:   "Validation failed",
339				Code:    http.StatusBadRequest,
340				Details: "Expiration date must be in the future",
341			})
342		}
343	
344		// Verify SKU exists
345		if _, err := h.repo.GetSKUByID(req.SKUID); err != nil {
346			return c.JSON(http.StatusNotFound, models.ErrorResponse{
347				Error:   "SKU not found",
348				Code:    http.StatusNotFound,
349				Details: "No SKU found with the given ID",
350			})
351		}
352	
353		// Create or update batch
354		batch := &models.InventoryBatch{
355			ID:             uuid.New().String(),
356			SKUID:          req.SKUID,
357			LotNumber:      req.LotNumber,
358			ExpirationDate: req.ExpirationDate,
359			QuantityOnHand: req.Quantity,
360			CreatedAt:      time.Now(),
361		}
362	
363		if err := h.repo.CreateBatch(batch); err != nil {
364			logrus.WithError(err).Error("Failed to create batch")
365			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
366				Error: "Failed to create batch",
367				Code:  http.StatusInternalServerError,
368			})
369		}
370	
371		// Create stock transaction
372		userID := middleware.GetUserID(c)
373		tx := &models.StockTransaction{
374			ID:          uuid.New().String(),
375			SKUID:       req.SKUID,
376			BatchID:     batch.ID,
377			Type:        "in",
378			Quantity:    req.Quantity,
379			ReasonCode:  req.ReasonCode,
380			PerformedBy: userID,
381			CreatedAt:   time.Now(),
382		}
383	
384		if err := h.repo.CreateStockTransaction(tx); err != nil {
385			logrus.WithError(err).Error("Failed to create stock transaction")
386			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
387				Error: "Failed to record transaction",
388				Code:  http.StatusInternalServerError,
389			})
390		}
391	
392		details, _ := json.Marshal(map[string]interface{}{
393			"sku_id":   req.SKUID,
394			"quantity": req.Quantity,
395			"batch_id": batch.ID,
396		})
397		h.repo.CreateAuditLog(&models.AuditLogEntry{
398			UserID:     userID,
399			Action:     "receive_inventory",
400			EntityType: "inventory_batch",
401			EntityID:   batch.ID,
402			Details:    details,
403		})
404	
405		logrus.WithFields(logrus.Fields{
406			"user_id":  userID,
407			"sku_id":   req.SKUID,
408			"batch_id": batch.ID,
409			"quantity": req.Quantity,
410		}).Info("Inventory received")
411	
412		return c.JSON(http.StatusCreated, map[string]interface{}{
413			"batch":       batch,
414			"transaction": tx,
415		})
416	}
