621			return c.JSON(http.StatusNotFound, models.ErrorResponse{
622				Error:   "Batch not found",
623				Code:    http.StatusNotFound,
624				Details: "No batch found with the given ID",
625			})
626		}
627	
628		// For negative adjustments, check we have enough stock
629		if req.Quantity < 0 && batch.QuantityOnHand+req.Quantity < 0 {
630			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
