885	// CompleteStocktake finalizes a stocktake and computes variance.
886	func (h *InventoryHandler) CompleteStocktake(c echo.Context) error {
887		id := c.Param("id")
888		if id == "" {
889			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
890				Error: "Stocktake ID is required",
891				Code:  http.StatusBadRequest,
892			})
893		}
894	
895		stocktake, err := h.repo.GetStocktakeByID(id)
896		if err != nil {
897			return c.JSON(http.StatusNotFound, models.ErrorResponse{
898				Error:   "Stocktake not found",
899				Code:    http.StatusNotFound,
900				Details: "No stocktake found with the given ID",
901			})
902		}
903	
904		if stocktake.Status != "open" {
905			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
906				Error:   "Stocktake not open",
907				Code:    http.StatusBadRequest,
908				Details: "Can only complete an open stocktake",
909			})
910		}
911	
912		if err := h.repo.CompleteStocktake(id); err != nil {
913			logrus.WithError(err).Error("Failed to complete stocktake")
914			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
915				Error: "Failed to complete stocktake",
916				Code:  http.StatusInternalServerError,
917			})
918		}
919	
920		// Fetch the completed stocktake
921		completed, err := h.repo.GetStocktakeByID(id)
922		if err != nil {
923			logrus.WithError(err).Error("Failed to fetch completed stocktake")
924			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
925				Error: "Stocktake completed but failed to retrieve result",
926				Code:  http.StatusInternalServerError,
927			})
928		}
929	
930		// Compute total variance summary
931		totalVariance := 0
932		for _, line := range completed.Lines {
933			totalVariance += line.Variance
934		}
935	
936		userID := middleware.GetUserID(c)
937		details, _ := json.Marshal(map[string]interface{}{
938			"stocktake_id":   id,
939			"total_variance": totalVariance,
940		})
941		h.repo.CreateAuditLog(&models.AuditLogEntry{
942			UserID:     userID,
943			Action:     "complete_stocktake",
944			EntityType: "stocktake",
945			EntityID:   id,
946			Details:    details,
947		})
948	
949		logrus.WithFields(logrus.Fields{
950			"user_id":        userID,
951			"stocktake_id":   id,
952			"total_variance": totalVariance,
953		}).Info("Stocktake completed")
954	
955		return c.JSON(http.StatusOK, map[string]interface{}{
956			"stocktake":      completed,
957			"total_variance": totalVariance,
958		})
959	}
