418	// Dispense handles inventory dispensing (stock out).
419	func (h *InventoryHandler) Dispense(c echo.Context) error {
420		var req models.DispenseRequest
421		if err := c.Bind(&req); err != nil {
422			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
423				Error: "Invalid request body",
424				Code:  http.StatusBadRequest,
425			})
426		}
427	
428		// Validate
429		if req.SKUID == "" {
430			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
431				Error:   "Validation failed",
432				Code:    http.StatusBadRequest,
433				Details: "SKU ID is required",
434			})
435		}
436		if req.BatchID == "" {
437			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
438				Error:   "Validation failed",
439				Code:    http.StatusBadRequest,
440				Details: "Batch ID is required",
441			})
442		}
443		if req.Quantity <= 0 {
444			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
445				Error:   "Validation failed",
446				Code:    http.StatusBadRequest,
447				Details: "Quantity must be greater than 0",
448			})
449		}
450		if req.ReasonCode == "" {
451			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
452				Error:   "Validation failed",
453				Code:    http.StatusBadRequest,
454				Details: "Reason code is required",
455			})
456		}
457	
458		// Get batch
459		batch, err := h.repo.GetBatchByID(req.BatchID)
460		if err != nil {
461			return c.JSON(http.StatusNotFound, models.ErrorResponse{
462				Error:   "Batch not found",
463				Code:    http.StatusNotFound,
464				Details: "No batch found with the given ID",
465			})
466		}
467	
468		// Check batch not expired
469		expDate, err := time.Parse("2006-01-02", batch.ExpirationDate)
470		if err == nil && !expDate.After(time.Now().Truncate(24*time.Hour)) {
471			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
472				Error:   "Batch expired",
473				Code:    http.StatusBadRequest,
474				Details: "Cannot dispense from an expired batch",
475			})
476		}
477	
478		// Check quantity available
479		if batch.QuantityOnHand < req.Quantity {
480			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
481				Error:   "Insufficient quantity",
482				Code:    http.StatusBadRequest,
483				Details: "Not enough stock in this batch to dispense the requested quantity",
484			})
485		}
486	
487		// Update batch quantity
488		batch.QuantityOnHand -= req.Quantity
489		if err := h.repo.UpdateBatch(batch); err != nil {
490			logrus.WithError(err).Error("Failed to update batch")
491			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
492				Error: "Failed to update batch",
493				Code:  http.StatusInternalServerError,
494			})
495		}
496	
497		// Create stock transaction
498		userID := middleware.GetUserID(c)
499		tx := &models.StockTransaction{
500			ID:             uuid.New().String(),
501			SKUID:          req.SKUID,
502			BatchID:        req.BatchID,
503			Type:           "out",
504			Quantity:       req.Quantity,
505			ReasonCode:     req.ReasonCode,
506			PrescriptionID: req.PrescriptionID,
507			PerformedBy:    userID,
508			CreatedAt:      time.Now(),
509		}
510	
511		if err := h.repo.CreateStockTransaction(tx); err != nil {
512			logrus.WithError(err).Error("Failed to create stock transaction")
513			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
514				Error: "Failed to record transaction",
515				Code:  http.StatusInternalServerError,
516			})
517		}
518	
519		details, _ := json.Marshal(map[string]interface{}{
520			"sku_id":   req.SKUID,
521			"batch_id": req.BatchID,
522			"quantity": req.Quantity,
523		})
524		h.repo.CreateAuditLog(&models.AuditLogEntry{
525			UserID:     userID,
526			Action:     "dispense_inventory",
527			EntityType: "inventory_batch",
528			EntityID:   req.BatchID,
529			Details:    details,
530		})
531	
532		logrus.WithFields(logrus.Fields{
533			"user_id":  userID,
534			"sku_id":   req.SKUID,
535			"batch_id": req.BatchID,
536			"quantity": req.Quantity,
537		}).Info("Inventory dispensed")
538	
539		return c.JSON(http.StatusOK, map[string]interface{}{
540			"batch":       batch,
541			"transaction": tx,
542		})
543	}
