574	// Adjust handles inventory adjustments with a reason code.
575	func (h *InventoryHandler) Adjust(c echo.Context) error {
576		var req struct {
577			SKUID      string `json:"sku_id"`
578			BatchID    string `json:"batch_id"`
579			Quantity   int    `json:"quantity"`
580			ReasonCode string `json:"reason_code"`
581		}
582		if err := c.Bind(&req); err != nil {
583			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
584				Error: "Invalid request body",
585				Code:  http.StatusBadRequest,
586			})
587		}
588	
589		if req.SKUID == "" {
590			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
591				Error:   "Validation failed",
592				Code:    http.StatusBadRequest,
593				Details: "SKU ID is required",
594			})
595		}
596		if req.BatchID == "" {
597			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
598				Error:   "Validation failed",
599				Code:    http.StatusBadRequest,
600				Details: "Batch ID is required",
601			})
602		}
603		if req.Quantity == 0 {
604			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
605				Error:   "Validation failed",
606				Code:    http.StatusBadRequest,
607				Details: "Quantity must be non-zero",
608			})
609		}
610		if req.ReasonCode == "" {
611			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
612				Error:   "Validation failed",
613				Code:    http.StatusBadRequest,
614				Details: "Reason code is required",
615			})
616		}
617	
618		// Get batch
619		batch, err := h.repo.GetBatchByID(req.BatchID)
620		if err != nil {
621			return c.JSON(http.StatusNotFound, models.ErrorResponse{
622				Error:   "Batch not found",
623				Code:    http.StatusNotFound,
624				Details: "No batch found with the given ID",
625			})
626		}
627	
628		// For negative adjustments, check we have enough stock
629		if req.Quantity < 0 && batch.QuantityOnHand+req.Quantity < 0 {
630			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
631				Error:   "Insufficient quantity",
632				Code:    http.StatusBadRequest,
633				Details: "Adjustment would result in negative stock",
634			})
635		}
636	
637		batch.QuantityOnHand += req.Quantity
638		if err := h.repo.UpdateBatch(batch); err != nil {
639			logrus.WithError(err).Error("Failed to update batch for adjustment")
640			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
641				Error: "Failed to adjust batch",
642				Code:  http.StatusInternalServerError,
643			})
644		}
645	
646		// Determine transaction type
647		txType := "adjustment_in"
648		absQty := req.Quantity
649		if req.Quantity < 0 {
650			txType = "adjustment_out"
651			absQty = -req.Quantity
652		}
653	
654		userID := middleware.GetUserID(c)
655		tx := &models.StockTransaction{
656			ID:          uuid.New().String(),
657			SKUID:       req.SKUID,
658			BatchID:     req.BatchID,
659			Type:        txType,
660			Quantity:    absQty,
661			ReasonCode:  req.ReasonCode,
662			PerformedBy: userID,
663			CreatedAt:   time.Now(),
664		}
665	
666		if err := h.repo.CreateStockTransaction(tx); err != nil {
667			logrus.WithError(err).Error("Failed to create adjustment transaction")
668			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
669				Error: "Failed to record adjustment transaction",
670				Code:  http.StatusInternalServerError,
671			})
672		}
673	
674		details, _ := json.Marshal(map[string]interface{}{
675			"sku_id":      req.SKUID,
676			"batch_id":    req.BatchID,
677			"quantity":    req.Quantity,
678			"reason_code": req.ReasonCode,
679		})
680		h.repo.CreateAuditLog(&models.AuditLogEntry{
681			UserID:     userID,
682			Action:     "adjust_inventory",
683			EntityType: "inventory_batch",
684			EntityID:   req.BatchID,
685			Details:    details,
686		})
687	
688		logrus.WithFields(logrus.Fields{
689			"user_id":  userID,
690			"batch_id": req.BatchID,
691			"quantity": req.Quantity,
692		}).Info("Inventory adjusted")
693	
694		return c.JSON(http.StatusOK, map[string]interface{}{
695			"batch":       batch,
696			"transaction": tx,
697		})
698	}
