797	// UpdateStocktakeLines updates the counted quantities for stocktake lines.
798	func (h *InventoryHandler) UpdateStocktakeLines(c echo.Context) error {
799		id := c.Param("id")
800		if id == "" {
801			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
802				Error: "Stocktake ID is required",
803				Code:  http.StatusBadRequest,
804			})
805		}
806	
807		// Verify stocktake exists and is open
808		stocktake, err := h.repo.GetStocktakeByID(id)
809		if err != nil {
810			return c.JSON(http.StatusNotFound, models.ErrorResponse{
811				Error:   "Stocktake not found",
812				Code:    http.StatusNotFound,
813				Details: "No stocktake found with the given ID",
814			})
815		}
816	
817		if stocktake.Status != "open" {
818			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
819				Error:   "Stocktake not open",
820				Code:    http.StatusBadRequest,
821				Details: "Can only update lines for an open stocktake",
822			})
823		}
824	
825		var req struct {
826			Lines []models.StocktakeLine `json:"lines"`
827		}
828		if err := c.Bind(&req); err != nil {
829			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
830				Error: "Invalid request body",
831				Code:  http.StatusBadRequest,
832			})
833		}
834	
835		if len(req.Lines) == 0 {
836			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
837				Error:   "Validation failed",
838				Code:    http.StatusBadRequest,
839				Details: "At least one line is required",
840			})
841		}
842	
843		// Set stocktake ID and compute variance for each line
844		for i := range req.Lines {
845			req.Lines[i].StocktakeID = id
846			if req.Lines[i].ID == "" {
847				req.Lines[i].ID = uuid.New().String()
848			}
849			req.Lines[i].Variance = req.Lines[i].CountedQty - req.Lines[i].SystemQty
850		}
851	
852		if err := h.repo.UpdateStocktakeLines(id, req.Lines); err != nil {
853			logrus.WithError(err).Error("Failed to update stocktake lines")
854			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
855				Error: "Failed to update stocktake lines",
856				Code:  http.StatusInternalServerError,
857			})
858		}
859	
860		userID := middleware.GetUserID(c)
861		details, _ := json.Marshal(map[string]interface{}{
862			"stocktake_id": id,
863			"lines_count":  len(req.Lines),
864		})
865		h.repo.CreateAuditLog(&models.AuditLogEntry{
866			UserID:     userID,
867			Action:     "update_stocktake_lines",
868			EntityType: "stocktake",
869			EntityID:   id,
870			Details:    details,
871		})
872	
873		logrus.WithFields(logrus.Fields{
874			"user_id":      userID,
875			"stocktake_id": id,
876			"lines":        len(req.Lines),
877		}).Info("Stocktake lines updated")
878	
879		return c.JSON(http.StatusOK, map[string]interface{}{
880			"message": "Stocktake lines updated successfully",
881			"lines":   req.Lines,
882		})
883	}
