729	// RefundStoredValue refunds stored value if within 7 days of the latest addition.
730	func (h *MemberHandler) RefundStoredValue(c echo.Context) error {
731		id := c.Param("id")
732		if id == "" {
733			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
734				Error: "Member ID is required",
735				Code:  http.StatusBadRequest,
736			})
737		}
738	
739		member, err := h.repo.GetMember(id)
740		if err != nil {
741			logrus.WithError(err).Error("Failed to get member for refund")
742			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
743				Error: "Failed to retrieve member",
744				Code:  http.StatusInternalServerError,
745			})
746		}
747		if member == nil {
748			return c.JSON(http.StatusNotFound, models.ErrorResponse{
749				Error:   "Member not found",
750				Code:    http.StatusNotFound,
751				Details: "No member found with the given ID",
752			})
753		}
754	
755		var req struct {
756			Amount float64 `json:"amount"`
757		}
758		if err := c.Bind(&req); err != nil {
759			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
760				Error: "Invalid request body",
761				Code:  http.StatusBadRequest,
762			})
763		}
764	
765		if req.Amount <= 0 {
766			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
767				Error:   "Validation failed",
768				Code:    http.StatusBadRequest,
769				Details: "Amount must be greater than 0",
770			})
771		}
772	
773		// Find the latest stored_value_add transaction by looking through recent transactions
774		transactions, _, err := h.repo.ListMemberTransactions(id, 1, 100)
775		if err != nil {
776			logrus.WithError(err).Error("Failed to list member transactions for refund check")
777			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
778				Error: "Failed to check transaction history",
779				Code:  http.StatusInternalServerError,
780			})
781		}
782	
783		var latestAdd *models.MemberTransaction
784		for i := range transactions {
785			if transactions[i].Type == "stored_value_add" {
786				latestAdd = &transactions[i]
787				break
788			}
789		}
790	
791		if latestAdd == nil {
792			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
793				Error:   "No stored value addition found",
794				Code:    http.StatusBadRequest,
795				Details: "No recent stored value addition to refund",
796			})
797		}
798	
799		// Check within 7 days
800		if time.Since(latestAdd.CreatedAt) > 7*24*time.Hour {
801			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
802				Error:   "Refund period expired",
803				Code:    http.StatusBadRequest,
804				Details: "Refunds must be requested within 7 days of the stored value addition",
805			})
806		}
807	
808		// Check member still has enough balance
809		if member.StoredValue < req.Amount {
810			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
811				Error:   "Insufficient balance for refund",
812				Code:    http.StatusBadRequest,
813				Details: "The stored value has already been partially or fully used",
814			})
815		}
816	
817		member.StoredValue -= req.Amount
818		if err := h.repo.UpdateMember(member); err != nil {
819			logrus.WithError(err).Error("Failed to refund stored value")
820			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
821				Error: "Failed to process refund",
822				Code:  http.StatusInternalServerError,
823			})
824		}
825	
826		userID := middleware.GetUserID(c)
827		tx := &models.MemberTransaction{
828			ID:          uuid.New().String(),
829			MemberID:    id,
830			Type:        "stored_value_refund",
831			Amount:      -req.Amount,
832			Description: fmt.Sprintf("Refunded stored value: $%.2f", req.Amount),
833			PerformedBy: userID,
834			CreatedAt:   time.Now(),
835		}
836		if err := h.repo.CreateMemberTransaction(tx); err != nil {
837			logrus.WithError(err).Error("Failed to create refund transaction")
838		}
839	
840		details, _ := json.Marshal(map[string]interface{}{
841			"amount": req.Amount,
842		})
843		h.repo.CreateAuditLog(&models.AuditLogEntry{
844			UserID:     userID,
845			Action:     "refund_stored_value",
846			EntityType: "member",
847			EntityID:   id,
848			Details:    details,
