307	// UnfreezeMember sets a member's status back to active and extends expiry.
308	func (h *MemberHandler) UnfreezeMember(c echo.Context) error {
309		id := c.Param("id")
310		if id == "" {
311			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
312				Error: "Member ID is required",
313				Code:  http.StatusBadRequest,
314			})
315		}
316	
317		member, err := h.repo.GetMember(id)
318		if err != nil {
319			logrus.WithError(err).Error("Failed to get member for unfreeze")
320			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
321				Error: "Failed to retrieve member",
322				Code:  http.StatusInternalServerError,
323			})
324		}
325		if member == nil {
326			return c.JSON(http.StatusNotFound, models.ErrorResponse{
327				Error:   "Member not found",
328				Code:    http.StatusNotFound,
329				Details: "No member found with the given ID",
330			})
331		}
332	
333		if member.Status != "frozen" {
334			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
335				Error:   "Member not frozen",
336				Code:    http.StatusBadRequest,
337				Details: "Can only unfreeze a frozen member",
338			})
339		}
340	
341		now := time.Now()
342		// Extend expires_at by the frozen duration
343		if member.FrozenAt != nil {
344			frozenDuration := now.Sub(*member.FrozenAt)
345			member.ExpiresAt = member.ExpiresAt.Add(frozenDuration)
346		}
347	
348		member.Status = "active"
349		member.FrozenAt = nil
350	
351		if err := h.repo.UpdateMember(member); err != nil {
352			logrus.WithError(err).Error("Failed to unfreeze member")
353			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
354				Error: "Failed to unfreeze member",
355				Code:  http.StatusInternalServerError,
356			})
357		}
358	
359		userID := middleware.GetUserID(c)
360		details, _ := json.Marshal(map[string]string{"member_id": id})
361		h.repo.CreateAuditLog(&models.AuditLogEntry{
362			UserID:     userID,
363			Action:     "unfreeze_member",
364			EntityType: "member",
365			EntityID:   id,
366			Details:    details,
367		})
368	
369		logrus.WithFields(logrus.Fields{
370			"user_id":   userID,
371			"member_id": id,
372		}).Info("Member unfrozen")
373	
374		return c.JSON(http.StatusOK, member)
375	}
