377	// RedeemBenefit redeems a benefit for a member.
378	func (h *MemberHandler) RedeemBenefit(c echo.Context) error {
379		id := c.Param("id")
380		if id == "" {
381			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
382				Error: "Member ID is required",
383				Code:  http.StatusBadRequest,
384			})
385		}
386	
387		member, err := h.repo.GetMember(id)
388		if err != nil {
389			logrus.WithError(err).Error("Failed to get member for redemption")
390			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
391				Error: "Failed to retrieve member",
392				Code:  http.StatusInternalServerError,
393			})
394		}
395		if member == nil {
396			return c.JSON(http.StatusNotFound, models.ErrorResponse{
397				Error:   "Member not found",
398				Code:    http.StatusNotFound,
399				Details: "No member found with the given ID",
400			})
401		}
402	
403		// Check member is not expired
404		if time.Now().After(member.ExpiresAt) {
405			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
406				Error:   "Membership expired",
407				Code:    http.StatusBadRequest,
408				Details: "This membership has expired",
409			})
410		}
411	
412		// Check member is not frozen
413		if member.Status == "frozen" {
414			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
415				Error:   "Membership frozen",
416				Code:    http.StatusBadRequest,
417				Details: "Cannot redeem benefits while membership is frozen",
418			})
419		}
420	
421		var req models.RedeemRequest
422		if err := c.Bind(&req); err != nil {
423			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
424				Error: "Invalid request body",
425				Code:  http.StatusBadRequest,
426			})
427		}
428	
429		userID := middleware.GetUserID(c)
430	
431		switch req.Type {
432		case "points_redeem":
433			if req.Amount <= 0 {
434				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
435					Error:   "Validation failed",
436					Code:    http.StatusBadRequest,
437					Details: "Amount must be greater than 0",
438				})
439			}
440			pointsNeeded := int(req.Amount)
441			if member.PointsBalance < pointsNeeded {
442				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
443					Error:   "Insufficient points",
444					Code:    http.StatusBadRequest,
445					Details: fmt.Sprintf("Available: %d, Requested: %d", member.PointsBalance, pointsNeeded),
446				})
447			}
448			member.PointsBalance -= pointsNeeded
449			if err := h.repo.UpdateMember(member); err != nil {
450				logrus.WithError(err).Error("Failed to update member points")
451				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
452					Error: "Failed to redeem points",
453					Code:  http.StatusInternalServerError,
454				})
455			}
456	
457			tx := &models.MemberTransaction{
458				ID:          uuid.New().String(),
459				MemberID:    id,
460				Type:        "points_redeem",
461				Amount:      -req.Amount,
462				Description: fmt.Sprintf("Redeemed %d points", pointsNeeded),
463				PerformedBy: userID,
464				CreatedAt:   time.Now(),
465			}
466			if err := h.repo.CreateMemberTransaction(tx); err != nil {
467				logrus.WithError(err).Error("Failed to create points redeem transaction")
468			}
469	
470		case "stored_value_use":
471			if req.Amount <= 0 {
472				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
473					Error:   "Validation failed",
474					Code:    http.StatusBadRequest,
475					Details: "Amount must be greater than 0",
476				})
477			}
478			if member.StoredValue < req.Amount {
479				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
480					Error:   "Insufficient stored value",
481					Code:    http.StatusBadRequest,
482					Details: fmt.Sprintf("Available: %.2f, Requested: %.2f", member.StoredValue, req.Amount),
483				})
484			}
485			member.StoredValue -= req.Amount
486			if err := h.repo.UpdateMember(member); err != nil {
487				logrus.WithError(err).Error("Failed to update member stored value")
488				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
489					Error: "Failed to redeem stored value",
490					Code:  http.StatusInternalServerError,
491				})
492			}
493	
494			tx := &models.MemberTransaction{
495				ID:          uuid.New().String(),
496				MemberID:    id,
497				Type:        "stored_value_use",
498				Amount:      -req.Amount,
499				Description: fmt.Sprintf("Used stored value: $%.2f", req.Amount),
500				PerformedBy: userID,
501				CreatedAt:   time.Now(),
502			}
503			if err := h.repo.CreateMemberTransaction(tx); err != nil {
504				logrus.WithError(err).Error("Failed to create stored value use transaction")
505			}
506	
507		case "session_redeem":
508			if req.PackageID == "" {
509				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
510					Error:   "Validation failed",
511					Code:    http.StatusBadRequest,
512					Details: "Package ID is required for session redemption",
513				})
514			}
515	
516			// Find the session package from the member's packages
517			packages, err := h.repo.GetSessionPackages(id)
518			if err != nil {
519				logrus.WithError(err).Error("Failed to get session packages")
520				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
521					Error: "Failed to retrieve session packages",
522					Code:  http.StatusInternalServerError,
523				})
524			}
525	
526			var pkg *models.SessionPackage
527			for i := range packages {
528				if packages[i].ID == req.PackageID {
529					pkg = &packages[i]
530					break
531				}
532			}
533			if pkg == nil {
534				return c.JSON(http.StatusNotFound, models.ErrorResponse{
535					Error:   "Session package not found",
536					Code:    http.StatusNotFound,
537					Details: "No session package found with the given ID",
538				})
539			}
540	
541			if pkg.RemainingSessions <= 0 {
542				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
543					Error:   "No sessions remaining",
544					Code:    http.StatusBadRequest,
545					Details: "This session package has no remaining sessions",
546				})
547			}
548			if time.Now().After(pkg.ExpiresAt) {
549				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
550					Error:   "Session package expired",
551					Code:    http.StatusBadRequest,
552					Details: "This session package has expired",
553				})
554			}
555	
556			pkg.RemainingSessions -= 1
557			if err := h.repo.UpdateSessionPackage(pkg); err != nil {
558				logrus.WithError(err).Error("Failed to update session package")
559				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
560					Error: "Failed to redeem session",
561					Code:  http.StatusInternalServerError,
562				})
563			}
564	
565			tx := &models.MemberTransaction{
566				ID:          uuid.New().String(),
567				MemberID:    id,
568				Type:        "session_redeem",
569				Amount:      -1,
570				Description: fmt.Sprintf("Redeemed 1 session from package %s", pkg.PackageName),
571				PerformedBy: userID,
572				CreatedAt:   time.Now(),
573			}
574			if err := h.repo.CreateMemberTransaction(tx); err != nil {
575				logrus.WithError(err).Error("Failed to create session redeem transaction")
576			}
577	
578		default:
579			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
580				Error:   "Validation failed",
581				Code:    http.StatusBadRequest,
582				Details: "Type must be one of: points_redeem, stored_value_use, session_redeem",
583			})
584		}
585	
586		details, _ := json.Marshal(map[string]interface{}{
587			"type":   req.Type,
588			"amount": req.Amount,
589		})
590		h.repo.CreateAuditLog(&models.AuditLogEntry{
591			UserID:     userID,
592			Action:     "redeem_benefit",
593			EntityType: "member",
594			EntityID:   id,
595			Details:    details,
596		})
597	
598		logrus.WithFields(logrus.Fields{
599			"user_id":   userID,
600			"member_id": id,
601			"type":      req.Type,
602		}).Info("Benefit redeemed")
603	
604		// Re-fetch member for updated state
605		member, _ = h.repo.GetMember(id)
606		return c.JSON(http.StatusOK, member)
607	}
