411	// GenerateStatement creates a new charge statement with status=draft.
412	func (h *ChargeHandler) GenerateStatement(c echo.Context) error {
413		var req struct {
414			PeriodStart string                  `json:"period_start"`
415			PeriodEnd   string                  `json:"period_end"`
416			LineItems   []models.ChargeLineItem `json:"line_items"`
417		}
418		if err := c.Bind(&req); err != nil {
419			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
420				Error: "Invalid request body",
421				Code:  http.StatusBadRequest,
422			})
423		}
424	
425		if req.PeriodStart == "" || req.PeriodEnd == "" {
426			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
427				Error:   "Validation failed",
428				Code:    http.StatusBadRequest,
429				Details: "Period start and end dates are required",
430			})
431		}
432	
433		if _, err := time.Parse("2006-01-02", req.PeriodStart); err != nil {
434			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
435				Error:   "Validation failed",
436				Code:    http.StatusBadRequest,
437				Details: "Invalid period_start format. Use YYYY-MM-DD",
438			})
439		}
440		if _, err := time.Parse("2006-01-02", req.PeriodEnd); err != nil {
441			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
442				Error:   "Validation failed",
443				Code:    http.StatusBadRequest,
444				Details: "Invalid period_end format. Use YYYY-MM-DD",
445			})
446		}
447	
448		// Calculate total amount from line items
449		var totalAmount float64
450		for i := range req.LineItems {
451			item := &req.LineItems[i]
452			item.Total = (item.Quantity * item.UnitPrice) + item.Surcharge + item.Tax
453			totalAmount += item.Total
454		}
455	
456		statement := &models.ChargeStatement{
457			ID:          uuid.New().String(),
458			PeriodStart: req.PeriodStart,
459			PeriodEnd:   req.PeriodEnd,
460			TotalAmount: totalAmount,
461			Status:      "draft",
462			CreatedAt:   time.Now(),
463		}
464	
465		if err := h.repo.CreateStatement(statement); err != nil {
466			logrus.WithError(err).Error("Failed to create statement")
467			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
468				Error: "Failed to create statement",
469				Code:  http.StatusInternalServerError,
470			})
471		}
472	
473		// Create line items
474		for i := range req.LineItems {
475			item := &req.LineItems[i]
476			item.ID = uuid.New().String()
477			item.StatementID = statement.ID
478			if err := h.repo.CreateLineItem(item); err != nil {
479				logrus.WithError(err).Error("Failed to create line item")
480			}
481		}
482	
483		userID := middleware.GetUserID(c)
484		details, _ := json.Marshal(map[string]interface{}{
485			"period_start": req.PeriodStart,
486			"period_end":   req.PeriodEnd,
487			"total_amount": totalAmount,
488		})
489		h.repo.CreateAuditLog(&models.AuditLogEntry{
490			UserID:     userID,
491			Action:     "generate_statement",
492			EntityType: "charge_statement",
493			EntityID:   statement.ID,
494			Details:    details,
495		})
496	
497		logrus.WithFields(logrus.Fields{
498			"user_id":      userID,
499			"statement_id": statement.ID,
500		}).Info("Statement generated")
501	
502		return c.JSON(http.StatusCreated, map[string]interface{}{
503			"statement":  statement,
504			"line_items": req.LineItems,
505		})
506	}
