240	// ImportRateTableCSV parses a CSV upload (columns: min,max,rate) into rate table tiers.
241	func (h *ChargeHandler) ImportRateTableCSV(c echo.Context) error {
242		file, err := c.FormFile("file")
243		if err != nil {
244			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
245				Error:   "File upload required",
246				Code:    http.StatusBadRequest,
247				Details: "A CSV file must be uploaded",
248			})
249		}
250	
251		src, err := file.Open()
252		if err != nil {
253			logrus.WithError(err).Error("Failed to open uploaded CSV")
254			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
255				Error: "Failed to process uploaded file",
256				Code:  http.StatusInternalServerError,
257			})
258		}
259		defer src.Close()
260	
261		reader := csv.NewReader(src)
262		records, err := reader.ReadAll()
263		if err != nil {
264			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
265				Error:   "Invalid CSV file",
266				Code:    http.StatusBadRequest,
267				Details: "Failed to parse CSV data",
268			})
269		}
270	
271		if len(records) < 2 {
272			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
273				Error:   "Empty CSV",
274				Code:    http.StatusBadRequest,
275				Details: "CSV must contain a header row and at least one data row",
276			})
277		}
278	
279		// Parse CSV rows into tier objects (columns: min, max, rate)
280		var tiers []map[string]interface{}
281		headers := records[0]
282		for _, row := range records[1:] {
283			tier := make(map[string]interface{})
284			for i, header := range headers {
285				if i < len(row) {
286					header = strings.TrimSpace(header)
287					val := strings.TrimSpace(row[i])
288					if num, err := strconv.ParseFloat(val, 64); err == nil {
289						tier[header] = num
290					} else {
291						tier[header] = val
292					}
293				}
294			}
295			tiers = append(tiers, tier)
296		}
297	
298		tiersJSON, err := json.Marshal(tiers)
299		if err != nil {
300			logrus.WithError(err).Error("Failed to marshal tiers")
301			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
302				Error: "Failed to process tier data",
303				Code:  http.StatusInternalServerError,
304			})
305		}
306	
307		// Create a new rate table with the parsed tiers
308		rt := &models.RateTable{
309			ID:    uuid.New().String(),
310			Name:  strings.TrimSuffix(file.Filename, ".csv"),
311			Type:  "imported",
312			Tiers: tiersJSON,
313		}
314	
315		if err := h.repo.CreateRateTable(rt); err != nil {
316			logrus.WithError(err).Error("Failed to create rate table from CSV")
317			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
318				Error: "Failed to import rate table from CSV",
319				Code:  http.StatusInternalServerError,
320			})
321		}
322	
323		userID := middleware.GetUserID(c)
324		details, _ := json.Marshal(map[string]interface{}{
325			"rate_table_id": rt.ID,
326			"tiers_count":   len(tiers),
327		})
328		h.repo.CreateAuditLog(&models.AuditLogEntry{
329			UserID:     userID,
330			Action:     "import_rate_table_csv",
331			EntityType: "rate_table",
332			EntityID:   rt.ID,
333			Details:    details,
334		})
335	
336		logrus.WithFields(logrus.Fields{
337			"user_id":       userID,
338			"rate_table_id": rt.ID,
339			"tiers":         len(tiers),
340		}).Info("Rate table tiers imported from CSV")
341	
342		return c.JSON(http.StatusCreated, rt)
343	}
