509	func (h *ChargeHandler) ReconcileStatement(c echo.Context) error {
510		id := c.Param("id")
511		if id == "" {
512			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
513				Error: "Statement ID is required",
514				Code:  http.StatusBadRequest,
515			})
516		}
517	
518		statement, err := h.repo.GetStatement(id)
519		if err != nil {
520			logrus.WithError(err).Error("Failed to get statement for reconciliation")
521			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
522				Error: "Failed to retrieve statement",
523				Code:  http.StatusInternalServerError,
524			})
525		}
526		if statement == nil {
527			return c.JSON(http.StatusNotFound, models.ErrorResponse{
528				Error:   "Statement not found",
529				Code:    http.StatusNotFound,
530				Details: "No statement found with the given ID",
531			})
532		}
533	
534		var req models.ReconcileRequest
535		if err := c.Bind(&req); err != nil {
536			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
537				Error: "Invalid request body",
538				Code:  http.StatusBadRequest,
539			})
540		}
541	
542		// Check if variance exceeds $25 and notes are required
543		if statement.TotalAmount > 25.00 && req.VarianceNotes == "" {
544			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
545				Error:   "Variance notes required",
546				Code:    http.StatusBadRequest,
547				Details: "Variance notes are required when the total exceeds $25.00",
548			})
549		}
550	
551		if req.VarianceNotes != "" {
552			statement.VarianceNotes = &req.VarianceNotes
553		}
554		statement.Status = "reconciled"
555	
556		if err := h.repo.UpdateStatement(statement); err != nil {
557			logrus.WithError(err).Error("Failed to reconcile statement")
558			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
559				Error: "Failed to reconcile statement",
560				Code:  http.StatusInternalServerError,
561			})
562		}
