585	// ApproveStatement implements two-step approval for statements.
586	func (h *ChargeHandler) ApproveStatement(c echo.Context) error {
587		id := c.Param("id")
588		if id == "" {
589			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
590				Error: "Statement ID is required",
591				Code:  http.StatusBadRequest,
592			})
593		}
594	
595		statement, err := h.repo.GetStatement(id)
596		if err != nil {
597			logrus.WithError(err).Error("Failed to get statement for approval")
598			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
599				Error: "Failed to retrieve statement",
600				Code:  http.StatusInternalServerError,
601			})
602		}
603		if statement == nil {
604			return c.JSON(http.StatusNotFound, models.ErrorResponse{
605				Error:   "Statement not found",
606				Code:    http.StatusNotFound,
607				Details: "No statement found with the given ID",
608			})
609		}
610	
611		userID := middleware.GetUserID(c)
612	
613		if statement.ApprovedBy1 == nil {
614			// First approval
615			statement.ApprovedBy1 = &userID
616			statement.Status = "pending_approval_2"
617		} else if statement.ApprovedBy2 == nil {
618			// Second approval -- must be different user
619			if *statement.ApprovedBy1 == userID {
620				return c.JSON(http.StatusForbidden, models.ErrorResponse{
621					Error:   "Cannot approve twice",
622					Code:    http.StatusForbidden,
623					Details: "The second approver must be a different user than the first",
624				})
625			}
626			statement.ApprovedBy2 = &userID
627			statement.Status = "approved"
628		} else {
629			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
630				Error:   "Statement already fully approved",
631				Code:    http.StatusBadRequest,
632				Details: "This statement has already been approved by two users",
633			})
634		}
635	
636		if err := h.repo.UpdateStatement(statement); err != nil {
637			logrus.WithError(err).Error("Failed to approve statement")
638			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
639				Error: "Failed to approve statement",
640				Code:  http.StatusInternalServerError,
641			})
642		}
643	
644		approvalStep := 1
645		if statement.ApprovedBy2 != nil {
646			approvalStep = 2
647		}
648		details, _ := json.Marshal(map[string]interface{}{
649			"statement_id":  id,
650			"approval_step": approvalStep,
651		})
652		h.repo.CreateAuditLog(&models.AuditLogEntry{
653			UserID:     userID,
654			Action:     "approve_statement",
655			EntityType: "charge_statement",
656			EntityID:   id,
657			Details:    details,
658		})
659	
660		logrus.WithFields(logrus.Fields{
661			"user_id":      userID,
662			"statement_id": id,
663		}).Info("Statement approved")
664	
665		return c.JSON(http.StatusOK, statement)
666	}
