668	// ExportStatement exports a statement as CSV with HMAC-SHA256 signature.
669	func (h *ChargeHandler) ExportStatement(c echo.Context) error {
670		id := c.Param("id")
671		if id == "" {
672			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
673				Error: "Statement ID is required",
674				Code:  http.StatusBadRequest,
675			})
676		}
677	
678		statement, err := h.repo.GetStatement(id)
679		if err != nil {
680			logrus.WithError(err).Error("Failed to get statement for export")
681			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
682				Error: "Failed to retrieve statement",
683				Code:  http.StatusInternalServerError,
684			})
685		}
686		if statement == nil {
687			return c.JSON(http.StatusNotFound, models.ErrorResponse{
688				Error:   "Statement not found",
689				Code:    http.StatusNotFound,
690				Details: "No statement found with the given ID",
691			})
692		}
693	
694		lineItems, err := h.repo.GetStatementLineItems(id)
695		if err != nil {
696			logrus.WithError(err).Error("Failed to get statement line items for export")
697			lineItems = []models.ChargeLineItem{}
698		}
699	
700		// Generate CSV content
701		var sb strings.Builder
702		writer := csv.NewWriter(&sb)
703	
704		// Header row
705		writer.Write([]string{"ID", "Period Start", "Period End", "Total Amount", "Status"})
706		writer.Write([]string{statement.ID, statement.PeriodStart, statement.PeriodEnd,
707			fmt.Sprintf("%.2f", statement.TotalAmount), statement.Status})
708	
709		writer.Write([]string{}) // blank line
710		writer.Write([]string{"Line Item ID", "Description", "Quantity", "Unit Price", "Surcharge", "Tax", "Total"})
711	
712		for _, item := range lineItems {
713			writer.Write([]string{
714				item.ID,
715				item.Description,
716				fmt.Sprintf("%.2f", item.Quantity),
717				fmt.Sprintf("%.2f", item.UnitPrice),
718				fmt.Sprintf("%.2f", item.Surcharge),
719				fmt.Sprintf("%.2f", item.Tax),
720				fmt.Sprintf("%.2f", item.Total),
721			})
722		}
723		writer.Flush()
724		content := []byte(sb.String())
725	
726		// Compute HMAC-SHA256 signature
727		hmacKey := []byte("medops-export-signing-key")
728		mac := hmac.New(sha256.New, hmacKey)
729		mac.Write(content)
730		signature := hex.EncodeToString(mac.Sum(nil))
731	
732		// Mark statement as exported
733		now := time.Now()
734		statement.ExportedAt = &now
735		h.repo.UpdateStatement(statement)
736	
737		userID := middleware.GetUserID(c)
738		details, _ := json.Marshal(map[string]string{
739			"statement_id": id,
740			"format":       "csv",
741		})
742		h.repo.CreateAuditLog(&models.AuditLogEntry{
743			UserID:     userID,
744			Action:     "export_statement",
745			EntityType: "charge_statement",
746			EntityID:   id,
747			Details:    details,
748		})
749	
750		c.Response().Header().Set("Content-Type", "text/csv")
751		c.Response().Header().Set("X-HMAC-Signature", signature)
752		c.Response().Header().Set("Content-Disposition", fmt.Sprintf("attachment; filename=\"statement_%s.csv\"", id))
753	
754		return c.Blob(http.StatusOK, "text/csv", content)
755	}
