1	import React from 'react';
2	import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
3	import { useAuth } from './hooks/useAuth';
4	import Layout from './components/common/Layout';
5	import LoginPage from './components/admin/LoginPage';
6	import DashboardPage from './components/admin/DashboardPage';
7	import UsersPage from './components/admin/UsersPage';
8	import SKUListPage from './components/inventory/SKUListPage';
9	import SKUDetailPage from './components/inventory/SKUDetailPage';
10	import StocktakePage from './components/inventory/StocktakePage';
11	import LearningPage from './components/learning/LearningPage';
12	import WorkOrdersPage from './components/workorders/WorkOrdersPage';
13	import WorkOrderDetailPage from './components/workorders/WorkOrderDetailPage';
14	import MembersPage from './components/members/MembersPage';
15	import MemberDetailPage from './components/members/MemberDetailPage';
16	import RateTablesPage from './components/charges/RateTablesPage';
17	import StatementsPage from './components/charges/StatementsPage';
18	
19	function ProtectedRoute({ children }: { children: React.ReactNode }) {
20	  const { isAuthenticated } = useAuth();
21	  if (!isAuthenticated) return <Navigate to="/login" replace />;
22	  return <Layout>{children}</Layout>;
23	}
24	
25	function RoleRoute({ children, roles }: { children: React.ReactNode; roles: string[] }) {
26	  const { user, isAuthenticated } = useAuth();
27	  if (!isAuthenticated) return <Navigate to="/login" replace />;
28	  if (user && !roles.includes(user.role)) return <Navigate to="/" replace />;
29	  return <Layout>{children}</Layout>;
30	}
31	
32	export default function App() {
33	  const { isAuthenticated } = useAuth();
34	
35	  return (
36	    <BrowserRouter>
37	      <Routes>
38	        <Route path="/login" element={isAuthenticated ? <Navigate to="/" replace /> : <LoginPage />} />
39	        <Route path="/" element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} />
40	        <Route path="/users" element={<RoleRoute roles={['system_admin']}><UsersPage /></RoleRoute>} />
41	        <Route path="/skus" element={<RoleRoute roles={['system_admin', 'inventory_pharmacist']}><SKUListPage /></RoleRoute>} />
42	        <Route path="/skus/:id" element={<RoleRoute roles={['system_admin', 'inventory_pharmacist']}><SKUDetailPage /></RoleRoute>} />
43	        <Route path="/stocktakes" element={<RoleRoute roles={['system_admin', 'inventory_pharmacist']}><StocktakePage /></RoleRoute>} />
44	        <Route path="/learning" element={<ProtectedRoute><LearningPage /></ProtectedRoute>} />
45	        <Route path="/work-orders" element={<ProtectedRoute><WorkOrdersPage /></ProtectedRoute>} />
46	        <Route path="/work-orders/:id" element={<ProtectedRoute><WorkOrderDetailPage /></ProtectedRoute>} />
47	        <Route path="/members" element={<RoleRoute roles={['system_admin', 'front_desk']}><MembersPage /></RoleRoute>} />
48	        <Route path="/members/:id" element={<RoleRoute roles={['system_admin', 'front_desk']}><MemberDetailPage /></RoleRoute>} />
49	        <Route path="/rate-tables" element={<RoleRoute roles={['system_admin']}><RateTablesPage /></RoleRoute>} />
50	        <Route path="/statements" element={<RoleRoute roles={['system_admin']}><StatementsPage /></RoleRoute>} />
51	        <Route path="*" element={<Navigate to="/" replace />} />
52	      </Routes>
53	    </BrowserRouter>
54	  );
55	}
