13	  const login = useCallback(async (username: string, password: string) => {
14	    setLoading(true);
15	    setError(null);
16	    try {
17	      const res = await authAPI.login(username, password);
18	      const { token, user: userData } = res.data;
19	      localStorage.setItem('medops_token', token);
20	      localStorage.setItem('medops_user', JSON.stringify(userData));
21	      setUser(userData);
22	      return userData;
23	    } catch (err: any) {
24	      const msg = err.response?.data?.error || 'Login failed';
25	      setError(msg);
26	      throw new Error(msg);
27	    } finally {
28	      setLoading(false);
29	    }
30	  }, []);
31	
32	  const logout = useCallback(async () => {
33	    try {
34	      await authAPI.logout();
