2	
3	import (
4		"os"
5		"strconv"
6	
7		"github.com/sirupsen/logrus"
8	)
9	
10	// defaultSecrets are the insecure fallback values used only in local/dev environments.
11	// In production, ALL of these MUST be overridden via environment variables.
12	var defaultSecrets = map[string]string{
13		"JWT_SECRET":       "medops-local-secret-change-in-production",
14		"ENCRYPT_KEY":      "0123456789abcdef0123456789abcdef",
15		"HMAC_SIGNING_KEY": "medops-export-signing-key-change-in-production",
16	}
17	
18	type Config struct {
19		Port           string
20		DatabaseURL    string
21		JWTSecret      string
22		EncryptKey     string
23		HMACKey        string
24		LogLevel       string
25		DataDir        string
26		MigrationsPath string
27	}
28	
29	func Load() *Config {
30		cfg := &Config{
31			Port:           getEnv("PORT", "8080"),
32			DatabaseURL:    getEnv("DATABASE_URL", "postgres://medops:medops@localhost:5432/medops?sslmode=disable"),
33			JWTSecret:      loadSecret("JWT_SECRET", "MedOps/JWTSecret", defaultSecrets["JWT_SECRET"]),
34			EncryptKey:     loadSecret("ENCRYPT_KEY", "MedOps/EncryptKey", defaultSecrets["ENCRYPT_KEY"]),
35			HMACKey:        loadSecret("HMAC_SIGNING_KEY", "MedOps/HMACKey", defaultSecrets["HMAC_SIGNING_KEY"]),
36			LogLevel:       getEnv("LOG_LEVEL", "info"),
37			DataDir:        getEnv("DATA_DIR", "/data/medops"),
38			MigrationsPath: getEnv("MIGRATIONS_PATH", "/app/migrations"),
39		}
40		warnIfDefaultSecrets(cfg)
41		return cfg
42	}
43	
44	// loadSecret resolves a secret using a three-tier priority:
45	//  1. OS credential store (Windows Credential Manager on Windows, no-op elsewhere)
46	//  2. Environment variable
47	//  3. Hard-coded development default (triggers a warning)
48	func loadSecret(envKey, credTarget, devDefault string) string {
49		// Tier 1: OS credential vault (Windows-only; returns "" on other platforms)
50		if val, err := loadFromCredentialStore(credTarget); err == nil && val != "" {
51			return val
52		}
53		// Tier 2: environment variable
54		if val := os.Getenv(envKey); val != "" {
55			return val
56		}
57		// Tier 3: insecure development default
58		return devDefault
59	}
60	
61	// warnIfDefaultSecrets emits a warning log for each secret that is still set to its insecure default.
62	func warnIfDefaultSecrets(cfg *Config) {
63		checks := map[string]string{
64			"JWT_SECRET":       cfg.JWTSecret,
65			"ENCRYPT_KEY":      cfg.EncryptKey,
66			"HMAC_SIGNING_KEY": cfg.HMACKey,
67		}
68		for key, val := range checks {
69			if def, ok := defaultSecrets[key]; ok && val == def {
70				logrus.WithField("env_var", key).Warn(
71					"SECURITY WARNING: secret is set to an insecure default value — set this environment variable before deploying to production",
72				)
73			}
74		}
75	}
76	
77	func getEnv(key, fallback string) string {
78		if v := os.Getenv(key); v != "" {
79			return v
80		}
81		return fallback
82	}
83	
84	func getEnvInt(key string, fallback int) int {
85		if v := os.Getenv(key); v != "" {
86			if i, err := strconv.Atoi(v); err == nil {
87				return i
88			}
89		}
90		return fallback
91	}
