func (r *Repository) decryptDecimal(data []byte) (float64, error) {
	ciphertext, err := hex.DecodeString(string(data))
	if err != nil {
		return 0, err
	}
	block, err := aes.NewCipher(r.encryptKey)
	if err != nil {
		return 0, err
	}
	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return 0, err
	}
	nonceSize := gcm.NonceSize()
