2	import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
3	import { useAuth } from './hooks/useAuth';
4	import Layout from './components/common/Layout';
5	import LoginPage from './components/admin/LoginPage';
6	import DashboardPage from './components/admin/DashboardPage';
7	import UsersPage from './components/admin/UsersPage';
8	import SKUListPage from './components/inventory/SKUListPage';
9	import SKUDetailPage from './components/inventory/SKUDetailPage';
10	import StocktakePage from './components/inventory/StocktakePage';
11	import LearningPage from './components/learning/LearningPage';
12	import WorkOrdersPage from './components/workorders/WorkOrdersPage';
13	import WorkOrderDetailPage from './components/workorders/WorkOrderDetailPage';
14	import MembersPage from './components/members/MembersPage';
15	import MemberDetailPage from './components/members/MemberDetailPage';
16	import RateTablesPage from './components/charges/RateTablesPage';
17	import StatementsPage from './components/charges/StatementsPage';
18	
19	function ProtectedRoute({ children }: { children: React.ReactNode }) {
20	  const { isAuthenticated } = useAuth();
21	  if (!isAuthenticated) return <Navigate to="/login" replace />;
22	  return <Layout>{children}</Layout>;
23	}
24	
25	function RoleRoute({ children, roles }: { children: React.ReactNode; roles: string[] }) {
26	  const { user, isAuthenticated } = useAuth();
27	  if (!isAuthenticated) return <Navigate to="/login" replace />;
