48	        <Route path="/work-orders" element={<ProtectedRoute><WorkOrdersPage /></ProtectedRoute>} />
49	        <Route path="/work-orders/:id" element={<ProtectedRoute><WorkOrderDetailPage /></ProtectedRoute>} />
50	        <Route path="/members" element={<RoleRoute roles={['system_admin', 'front_desk']}><MembersPage /></RoleRoute>} />
51	        <Route path="/members/:id" element={<RoleRoute roles={['system_admin', 'front_desk']}><MemberDetailPage /></RoleRoute>} />
52	        <Route path="/rate-tables" element={<RoleRoute roles={['system_admin']}><RateTablesPage /></RoleRoute>} />
53	        <Route path="/statements" element={<RoleRoute roles={['system_admin']}><StatementsPage /></RoleRoute>} />
54	        <Route path="/system-config" element={<RoleRoute roles={['system_admin']}><DashboardPage /></RoleRoute>} />
55	        <Route path="*" element={<Navigate to="/" replace />} />
56	      </Routes>
57	    </BrowserRouter>
58	  );
59	}
