1	/**
2	 * Electron main process — MedOps Offline Operations Console
3	 * Handles window lifecycle, backend subprocess, tray, and IPC.
4	 */
5	
6	import {
7	  app,
8	  BrowserWindow,
9	  ipcMain,
10	  dialog,
11	  shell,
12	  nativeImage,
13	  session,
14	} from 'electron';
15	import { join } from 'path';
16	import { existsSync } from 'fs';
17	import { spawn, ChildProcess } from 'child_process';
18	import { setupTray, cleanupTray } from './tray';
19	
20	// ─── Constants ────────────────────────────────────────────────────────────────
21	
22	const IS_DEV = !app.isPackaged;
23	const BACKEND_PORT = parseInt(process.env.BACKEND_PORT ?? '8080', 10);
24	const BACKEND_URL = `http://localhost:${BACKEND_PORT}`;
25	
26	// ─── State ────────────────────────────────────────────────────────────────────
27	
28	let mainWindow: BrowserWindow | null = null;
29	let backendProcess: ChildProcess | null = null;
30	const windows = new Set<BrowserWindow>();
31	
32	// ─── Backend subprocess ───────────────────────────────────────────────────────
33	
34	function getBackendBinary(): string | null {
35	  if (IS_DEV) return null; // dev mode: backend runs externally (Docker / go run)
36	
37	  const binaryName = process.platform === 'win32' ? 'medops-server.exe' : 'medops-server';
38	  const candidate = join(process.resourcesPath, 'backend', binaryName);
39	  return existsSync(candidate) ? candidate : null;
40	}
41	
42	function startBackend(): Promise<void> {
43	  return new Promise((resolve, reject) => {
44	    const binary = getBackendBinary();
45	
46	    if (!binary) {
47	      // Dev mode or binary not found — assume backend is already running
48	      console.log('[main] Backend binary not found — assuming external backend at', BACKEND_URL);
49	      waitForBackend(20, resolve, reject);
50	      return;
51	    }
52	
53	    console.log('[main] Starting backend:', binary);
54	
55	    const userDataDir = join(app.getPath('userData'), 'data');
56	    const migrationsPath = join(process.resourcesPath, 'backend', 'migrations');
57	
58	    backendProcess = spawn(binary, [], {
59	      env: {
60	        ...process.env,
61	        PORT: String(BACKEND_PORT),
62	        MIGRATIONS_PATH: migrationsPath,
63	        DATA_DIR: userDataDir,
64	        LOG_LEVEL: 'info',
65	      },
66	      stdio: ['ignore', 'pipe', 'pipe'],
67	    });
68	
69	    backendProcess.stdout?.on('data', (d: Buffer) =>
70	      console.log('[backend]', d.toString().trim()),
71	    );
72	    backendProcess.stderr?.on('data', (d: Buffer) =>
73	      console.error('[backend]', d.toString().trim()),
74	    );
75	    backendProcess.on('exit', (code) => {
76	      console.warn('[main] Backend exited with code', code);
77	      backendProcess = null;
78	    });
79	
80	    // Wait for backend to become ready
81	    waitForBackend(60, resolve, reject);
82	  });
83	}
84	
85	function waitForBackend(maxAttempts: number, resolve: () => void, reject: (e: Error) => void): void {
86	  let attempts = 0;
87	  const check = (): void => {
88	    attempts++;
89	    fetch(`${BACKEND_URL}/api/v1/health`)
90	      .then((r) => {
91	        if (r.ok) {
92	          console.log('[main] Backend ready after', attempts, 'attempt(s)');
93	          resolve();
94	        } else {
95	          retry();
96	        }
97	      })
98	      .catch(() => retry());
99	  };
100	  const retry = (): void => {
101	    if (attempts >= maxAttempts) {
102	      reject(new Error(`Backend did not become ready after ${maxAttempts} attempts`));
103	      return;
104	    }
105	    setTimeout(check, 1000);
106	  };
107	  check();
108	}
109	
110	function stopBackend(): void {
111	  if (backendProcess) {
112	    console.log('[main] Stopping backend...');
113	    backendProcess.kill('SIGTERM');
114	    backendProcess = null;
115	  }
116	}
117	
118	// ─── Window factory ───────────────────────────────────────────────────────────
119	
120	function createAppIcon(): Electron.NativeImage {
121	  // 32x32 teal square encoded as base64 PNG
122	  const ICON_B64 =
123	    'iVBORw0KGgoAAAANSUhEUgAAACAAAAAgCAYAAABzenr0AAAAAXNSR0IArs4c6QAAAARnQU1BAACx' +
124	    'jwv8YQUAAAAJcEhZcwAADsMAAA7DAcdvqGQAAABGSURBVFhH7c4xAQAgDASh/UdrjuAIXCTZ7AIA' +
125	    'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA8G0BtAABhiK3KeEAAAAASUVORK5CYII=';
126	  return nativeImage.createFromBuffer(Buffer.from(ICON_B64, 'base64'));
127	}
128	
129	function createWindow(options: { url?: string; title?: string } = {}): BrowserWindow {
130	  const icon = createAppIcon();
131	  const win = new BrowserWindow({
132	    width: 1280,
133	    height: 800,
134	    minWidth: 960,
135	    minHeight: 600,
136	    title: options.title ?? 'MedOps Offline Operations Console',
137	    icon,
138	    backgroundColor: '#f5f7fa',
139	    webPreferences: {
140	      preload: join(__dirname, 'preload.cjs'),
141	      contextIsolation: true,
142	      nodeIntegration: false,
143	      sandbox: true,
144	    },
145	    show: false, // shown after 'ready-to-show'
146	  });
147	
148	  const url = options.url ?? (IS_DEV ? `${BACKEND_URL}` : join(__dirname, '..', 'dist', 'index.html'));
149	
150	  if (IS_DEV || url.startsWith('http')) {
151	    win.loadURL(url);
152	  } else {
153	    win.loadFile(url);
154	  }
155	
156	  win.once('ready-to-show', () => win.show());
157	
158	  win.on('closed', () => {
159	    windows.delete(win);
160	    if (win === mainWindow) mainWindow = null;
161	  });
162	
163	  // Open external links in the OS browser
164	  win.webContents.setWindowOpenHandler(({ url: targetUrl }) => {
165	    if (targetUrl.startsWith('http')) shell.openExternal(targetUrl);
166	    return { action: 'deny' };
167	  });
168	
169	  windows.add(win);
170	  return win;
171	}
172	
173	// ─── IPC handlers ─────────────────────────────────────────────────────────────
174	
175	function registerIPC(): void {
176	  ipcMain.on('window:minimize', (e) => BrowserWindow.fromWebContents(e.sender)?.minimize());
177	  ipcMain.on('window:maximize', (e) => {
178	    const win = BrowserWindow.fromWebContents(e.sender);
179	    if (!win) return;
180	    win.isMaximized() ? win.unmaximize() : win.maximize();
181	  });
182	  ipcMain.on('window:close', (e) => BrowserWindow.fromWebContents(e.sender)?.close());
183	
184	  ipcMain.on('window:openNew', (_e, opts: { url?: string; title?: string } = {}) => {
185	    createWindow(opts);
186	  });
187	
188	  ipcMain.on('screen:lock', (e) => {
189	    // Reload the renderer so it hits the auth guard and redirects to /login
190	    BrowserWindow.fromWebContents(e.sender)?.webContents.reload();
191	  });
192	
193	  ipcMain.handle('app:info', () => ({
194	    version: app.getVersion(),
195	    platform: process.platform,
196	    isPackaged: app.isPackaged,
197	    backendUrl: BACKEND_URL,
198	  }));
199	
200	  ipcMain.on('shell:openExternal', (_e, url: string) => {
201	    if (typeof url === 'string' && url.startsWith('http')) {
202	      shell.openExternal(url);
203	    }
204	  });
205	
206	  ipcMain.on('dialog:showMessage', async (_e, opts: Electron.MessageBoxOptions) => {
207	    if (mainWindow) await dialog.showMessageBox(mainWindow, opts);
208	  });
209	}
210	
211	// ─── App lifecycle ────────────────────────────────────────────────────────────
212	
213	app.whenReady().then(async () => {
214	  // Security: block navigation to unexpected origins
215	  session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
216	    callback({
217	      responseHeaders: {
218	        ...details.responseHeaders,
219	        'Content-Security-Policy': [
220	          `default-src 'self' ${BACKEND_URL}; script-src 'self' 'unsafe-inline'; style-src 'self' 'unsafe-inline'; img-src 'self' data:`,
221	        ],
222	      },
223	    });
224	  });
225	
226	  registerIPC();
227	
228	  try {
229	    await startBackend();
230	  } catch (err) {
231	    await dialog.showErrorBox(
232	      'Backend Error',
233	      `Could not start the MedOps backend service.\n\n${(err as Error).message}\n\nPlease ensure PostgreSQL is running on localhost:5432 and try again.`,
234	    );
235	    app.quit();
236	    return;
237	  }
238	
239	  mainWindow = createWindow();
240	
241	  setupTray({
242	    icon: createAppIcon(),
243	    onOpen: () => {
244	      if (mainWindow) {
245	        mainWindow.show();
246	        mainWindow.focus();
247	      } else {
248	        mainWindow = createWindow();
249	      }
250	    },
251	    onLock: () => {
252	      for (const win of windows) {
253	        win.webContents.executeJavaScript(
254	          `localStorage.removeItem('medops_token'); window.location.href = '/login';`,
255	        );
256	      }
257	    },
258	    onNewWindow: () => createWindow(),
259	    onQuit: () => app.quit(),
260	  });
261	
262	  app.on('activate', () => {
263	    // macOS: re-create window when dock icon is clicked
264	    if (BrowserWindow.getAllWindows().length === 0) mainWindow = createWindow();
265	  });
266	});
267	
268	app.on('window-all-closed', () => {
269	  // On macOS apps stay alive in the menu bar; on other platforms quit.
270	  if (process.platform !== 'darwin') app.quit();
271	});
272	
273	app.on('before-quit', () => {
274	  cleanupTray();
275	  stopBackend();
276	});
277	
278	// Prevent multiple instances
279	const gotLock = app.requestSingleInstanceLock();
280	if (!gotLock) {
281	  app.quit();
282	} else {
283	  app.on('second-instance', () => {
284	    if (mainWindow) {
285	      if (mainWindow.isMinimized()) mainWindow.restore();
286	      mainWindow.focus();
287	    }
288	  });
289	}
