40	// loadSecret resolves a secret using a two-tier priority:
41	//  1. OS credential store (Windows Credential Manager on Windows, no-op elsewhere)
42	//  2. Environment variable
43	//
44	// Returns an empty string if neither source provides a value.
45	// The caller (enforceRequiredSecrets) will fatal if the result is empty.
46	func loadSecret(envKey, credTarget string) string {
47		// Tier 1: OS credential vault (Windows-only; returns "" on other platforms)
48		if val, err := loadFromCredentialStore(credTarget); err == nil && val != "" {
49			return val
50		}
51		// Tier 2: environment variable
52		return os.Getenv(envKey)
53	}
54	
55	// enforceRequiredSecrets fatals if any required secret is empty, preventing
56	// the application from starting without proper secret provisioning.
57	func enforceRequiredSecrets(cfg *Config) {
58		missing := false
59		secrets := map[string]string{
60			"JWT_SECRET":       cfg.JWTSecret,
61			"ENCRYPT_KEY":      cfg.EncryptKey,
62			"HMAC_SIGNING_KEY": cfg.HMACKey,
63		}
64		for _, key := range requiredSecrets {
65			if secrets[key] == "" {
66				logrus.WithField("env_var", key).Fatal(
67					"SECURITY: required secret is not set — set this environment variable before starting the application",
68				)
69				missing = true
70			}
71		}
72		if missing {
73			os.Exit(1)
74		}
75	}
