27	// New creates a new Repository with the given database connection and AES-256 encryption key.
28	func New(db *sql.DB, encryptKey string) *Repository {
29		var k [32]byte
30		copy(k[:], []byte(encryptKey))
31		return &Repository{DB: db, encryptKey: k[:]}
32	}
