34	// encryptDecimal encrypts a float64 monetary value using AES-256-GCM.
35	func (r *Repository) encryptDecimal(value float64) ([]byte, error) {
36		block, err := aes.NewCipher(r.encryptKey)
37		if err != nil {
38			return nil, err
39		}
40		gcm, err := cipher.NewGCM(block)
41		if err != nil {
42			return nil, err
43		}
44		nonce := make([]byte, gcm.NonceSize())
45		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
46			return nil, err
47		}
48		plaintext := []byte(strconv.FormatFloat(value, 'f', 2, 64))
49		ciphertext := gcm.Seal(nonce, nonce, plaintext, nil)
50		return []byte(hex.EncodeToString(ciphertext)), nil
51	}
52	
53	// decryptDecimal decrypts an AES-256-GCM encrypted monetary value back to float64.
54	func (r *Repository) decryptDecimal(data []byte) (float64, error) {
55		ciphertext, err := hex.DecodeString(string(data))
56		if err != nil {
57			return 0, err
58		}
59		block, err := aes.NewCipher(r.encryptKey)
60		if err != nil {
61			return 0, err
62		}
63		gcm, err := cipher.NewGCM(block)
64		if err != nil {
65			return 0, err
66		}
67		nonceSize := gcm.NonceSize()
68		if len(ciphertext) < nonceSize {
69			return 0, fmt.Errorf("ciphertext too short")
70		}
71		plaintext, err := gcm.Open(nil, ciphertext[:nonceSize], ciphertext[nonceSize:], nil)
72		if err != nil {
73			return 0, err
74		}
75		return strconv.ParseFloat(string(plaintext), 64)
76	}
