761	// ListWorkOrders returns paginated work orders with optional status and assignee filters.
762	func (r *Repository) ListWorkOrders(status string, assignedTo string, page, pageSize int) ([]models.WorkOrder, int, error) {
763		offset := (page - 1) * pageSize
764	
765		query := `SELECT id, submitted_by, assigned_to, trade, priority, sla_deadline, status, description, location, parts_cost, labor_cost, rating, closed_at, created_at,
766		                 COUNT(*) OVER() AS total
767		          FROM work_orders WHERE 1=1`
768		var args []interface{}
769		argIdx := 1
770	
771		if status != "" {
772			query += fmt.Sprintf(" AND status = $%d", argIdx)
773			args = append(args, status)
774			argIdx++
775		}
776		if assignedTo != "" {
777			query += fmt.Sprintf(" AND assigned_to = $%d", argIdx)
778			args = append(args, assignedTo)
779			argIdx++
780		}
781	
782		query += fmt.Sprintf(" ORDER BY created_at DESC LIMIT $%d OFFSET $%d", argIdx, argIdx+1)
783		args = append(args, pageSize, offset)
784	
785		rows, err := r.DB.Query(query, args...)
786		if err != nil {
787			return nil, 0, fmt.Errorf("list work orders: %w", err)
788		}
789		defer rows.Close()
790	
791		var orders []models.WorkOrder
792		var total int
793		for rows.Next() {
794			var wo models.WorkOrder
795			if err := rows.Scan(&wo.ID, &wo.SubmittedBy, &wo.AssignedTo, &wo.Trade, &wo.Priority, &wo.SLADeadline, &wo.Status, &wo.Description, &wo.Location, &wo.PartsCost, &wo.LaborCost, &wo.Rating, &wo.ClosedAt, &wo.CreatedAt, &total); err != nil {
796				return nil, 0, fmt.Errorf("list work orders scan: %w", err)
797			}
798			orders = append(orders, wo)
799		}
800		return orders, total, rows.Err()
801	}
