107	// RequireRole returns middleware that checks whether the authenticated user's role
108	// is among the allowed roles. Returns 403 Forbidden if not.
109	func RequireRole(roles ...string) echo.MiddlewareFunc {
110		allowed := make(map[string]struct{}, len(roles))
111		for _, r := range roles {
112			allowed[r] = struct{}{}
113		}
114	
115		return func(next echo.HandlerFunc) echo.HandlerFunc {
116			return func(c echo.Context) error {
117				userRole := GetUserRole(c)
118				if _, ok := allowed[userRole]; !ok {
119					return c.JSON(http.StatusForbidden, models.ErrorResponse{
120						Error:   "Insufficient permissions",
121						Code:    http.StatusForbidden,
122						Details: fmt.Sprintf("Role '%s' is not authorized for this resource", userRole),
123					})
124				}
125				return next(c)
126			}
127		}
128	}
