130	// RequestLogger returns middleware that logs each request using logrus with structured fields.
131	func RequestLogger() echo.MiddlewareFunc {
132		logger := logrus.New()
133		logger.SetFormatter(&logrus.JSONFormatter{})
134	
135		return func(next echo.HandlerFunc) echo.HandlerFunc {
136			return func(c echo.Context) error {
137				start := time.Now()
138	
139				err := next(c)
140				if err != nil {
141					c.Error(err)
142				}
143	
144				latency := time.Since(start)
145				req := c.Request()
146				res := c.Response()
147	
148				fields := logrus.Fields{
149					"method":     req.Method,
150					"path":       req.URL.Path,
151					"status":     res.Status,
152					"latency_ms": latency.Milliseconds(),
153					"remote_ip":  c.RealIP(),
154				}
155	
156				if userID := GetUserID(c); userID != "" {
157					fields["user_id"] = userID
158				}
159	
160				entry := logger.WithFields(fields)
161	
162				status := res.Status
163				switch {
164				case status >= 500:
165					entry.Error("Server error")
166				case status >= 400:
167					entry.Warn("Client error")
168				default:
169					entry.Info("Request handled")
170				}
171	
172				return nil
173			}
174		}
175	}
176	
177	// Recovery returns middleware that recovers from panics, logs the error, and returns a 500 response.
178	func Recovery() echo.MiddlewareFunc {
179		logger := logrus.New()
180		logger.SetFormatter(&logrus.JSONFormatter{})
181	
182		return func(next echo.HandlerFunc) echo.HandlerFunc {
183			return func(c echo.Context) error {
184				defer func() {
185					if r := recover(); r != nil {
186						logger.WithFields(logrus.Fields{
187							"panic":  fmt.Sprintf("%v", r),
188							"method": c.Request().Method,
189							"path":   c.Request().URL.Path,
190						}).Error("Panic recovered")
191	
192						c.JSON(http.StatusInternalServerError, models.ErrorResponse{
193							Error: "Internal server error",
194							Code:  http.StatusInternalServerError,
195						})
196					}
197				}()
198	
199				return next(c)
200			}
201		}
202	}
