258	func (h *WorkOrderHandler) UpdateWorkOrder(c echo.Context) error {
259		id := c.Param("id")
260		if id == "" {
261			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
262				Error: "Work order ID is required",
263				Code:  http.StatusBadRequest,
264			})
265		}
266	
267		wo, err := h.repo.GetWorkOrderByID(id)
268		if err != nil {
269			return c.JSON(http.StatusNotFound, models.ErrorResponse{
270				Error:   "Work order not found",
271				Code:    http.StatusNotFound,
272				Details: "No work order found with the given ID",
273			})
274		}
275	
276		var body struct {
277			Status      *string `json:"status"`
278			Description *string `json:"description"`
279			Location    *string `json:"location"`
280			AssignedTo  *string `json:"assigned_to"`
281		}
282		if err := c.Bind(&body); err != nil {
283			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
284				Error: "Invalid request body",
285				Code:  http.StatusBadRequest,
286			})
287		}
288	
289		if body.Status != nil {
290			validStatuses := map[string]bool{
291				"submitted": true, "dispatched": true, "in_progress": true,
292				"completed": true, "closed": true,
293			}
294			if !validStatuses[*body.Status] {
295				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
296					Error:   "Validation failed",
297					Code:    http.StatusBadRequest,
